def _check_max_length_choices(self, **kwargs):
    if self.max_length is not None and self.choices:
        choice_max_length = 0
        for choice_value, _ in self.flatchoices:
            choice_length = len(str(choice_value))
            if choice_length > choice_max_length:
                choice_max_length = choice_length
        if choice_max_length > self.max_length:
            return [
                checks.Error(
                    "'max_length' is too small to fit the longest value "
                    "in 'choices' (%d characters)." % choice_max_length,
                    obj=self,
                    id='fields.E122',
                )
            ]
    return []

